select id, ext_type, user_id, tg_user_id, super_user_id, channel_id, order_no, order_type, account_type,
       type, amount, old_amount, new_amount, remark, operator, sign_time, sign, create_time
from t_user_ext_change
where id = #{id}
limit 1;

select
    ifnull(sum(amount),0)

from t_user_ext_change where type = #{type} and   user_id =#{userId} and create_time >= #{startTime} and create_time <= #{endTime}

select l.id, l.ext_type, l.user_id, l.tg_user_id, l.order_no, l.order_type, l.account_type, l.type, l.amount, l.old_amount, l.new_amount, l.remark,
l.operator, l.sign_time, l.sign, l.create_time
from t_user_ext_change l left join t_user u on l.user_id = u.user_id


    and u.channel_id = #{channelId}



    and l.create_time BETWEEN #{startTime} AND #{endTime}

select
 ifnull(SUM(CASE WHEN ext_type = 4 AND order_type = 2 AND type = 3 AND account_type = 2 THEN amount ELSE 0 END),0) as alreadyRebateAmount,
 ifnull(SUM(CASE WHEN ext_type = 5 AND order_type = 2 AND type = 4 AND account_type = 2 THEN amount ELSE 0 END),0) as alreadyReturnCommissionAmount
 from t_user_ext_change


         AND user_id = #{userId}


         AND create_time BETWEEN #{startTime} AND #{endTime}

select
ifnull(SUM(CASE WHEN l.ext_type = 4 AND l.order_type = 2 AND l.type = 3 AND l.account_type = 2 THEN l.amount ELSE 0 END),0) as alreadyRebateAmount,
ifnull(SUM(CASE WHEN l.ext_type = 5 AND l.order_type = 2 AND l.type = 4 AND l.account_type = 2 THEN l.amount ELSE 0 END),0) as alreadyReturnCommissionAmount
from t_user_ext_change l left join t_user u on l.user_id = u.user_id


        and u.channel_id = #{channelId}


        and l.create_time BETWEEN #{startTime} AND #{endTime}

